<script setup>
import { ref, onUnmounted, defineProps } from 'vue';
// Definir la prop productId
const props = defineProps({
    productPhotos: {
        type: Number,
        required: true
    }
});
console.log(props.productPhotos);
const images = [
    {
        src: 'https://petapixel.com/assets/uploads/2022/12/what-is-unsplash-800x420.jpg',
        alt: 'Image 1',
    },
    {
        src: 'https://petapixel.com/assets/uploads/2022/12/image13-1-800x536.jpg',
        alt: 'Image 2',
    },
    {
        src: 'https://petapixel.com/assets/uploads/2022/12/image11-1-800x534.jpg',
        alt: 'Image 3',
    },
];

const currentSliderIndex = ref(0);
let intervalId;

const isTimerPaused = ref(false);

const nextSlide = () => {
    currentSliderIndex.value = (currentSliderIndex.value + 1) % images.length;
    isTimerPaused ? '' : startSlider()
};

const prevSlide = () => {
    currentSliderIndex.value = (currentSliderIndex.value - 1 + images.length) % images.length;
    isTimerPaused ? '' : startSlider()
};

onUnmounted(() => {
    clearInterval(intervalId);
});
</script>

<template>
    <div class="h-screen flex flex-col">
      <div class="slider flex h-[100%]">
        <div class="flex flex-col items-center justify-center relative w-[500px] h-[300px] m-auto">
          <template v-for="(productPhoto, index) in productPhotos" :key="index">
            <transition name="fade">
              <img :src="productPhoto" class="aspect-[16/9] w-full h-full object-cover absolute" v-if="index === currentSliderIndex" />
            </transition>
          </template>
  
          <button class="fas fa-caret-right absolute right-0 top-1/2 text-4xl m-2 cursor-pointer text-white z-50"
                  @click="nextSlide">></button>
          <button class="fas fa-caret-left absolute left-0 top-1/2 text-4xl m-2 cursor-pointer text-white z-50"
                  @click="prevSlide">
            <</button>
        </div>
      </div>
    </div>
  </template>

        <style>

        .fade-enter-active,
        .fade-leave-active {
            transition: opacity 1s, transform 1s;
        }

        .fade-enter-from,
        .fade-leave-to {
            opacity: 0;
            transform: translateX(0);
        }
    </style>